import { useIntl } from 'react-intl';


import { CopyPermissionsButton } from './CopyPermissionsButton.js';
import { Button } from '../../../../buttons/button/Button.js';
import { MessageContainer } from '../../../../content/message-container/MessageContainer.js';
import { useFormFieldMessagesContext } from '../../../../forms/forms-core/hooks/useFormFieldMessagesContext.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { useSegmentsUIContext } from '../../contexts/SegmentsUI/SegmentsUIContext.js';
import { useSegments } from '../../hooks/useSegments.js';
import { SEGMENTSELECTOR_MESSAGES } from '../../segmentMessages.js';

/**
 * Hint shown when the user has no access to segments.
 * @internal
 */
export const NoAccessHint = ({ readOnly = false }: { readOnly?: boolean }) => {
  const intl = useIntl();
  const { removeAllSegments } = useSegments();
  const { removeAllUISegments } = useSegmentsUIContext();
  const { state } = useFormFieldMessagesContext();
  const color = state?.showError ? 'critical' : 'neutral';

  return (
    <MessageContainer variant={color}>
      <MessageContainer.Prefix />
      <MessageContainer.Title>
        {color === 'neutral'
          ? intl.formatMessage(SEGMENTSELECTOR_MESSAGES.noReadAccess)
          : intl.formatMessage(SEGMENTSELECTOR_MESSAGES.noReadAndWriteAccess)}
      </MessageContainer.Title>
      <MessageContainer.Description>
        {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.copyDetailsHint)}
      </MessageContainer.Description>
      <MessageContainer.Actions>
        <Flex>
          {!readOnly && (
            <Button
              variant="emphasized"
              color={color}
              onClick={() => {
                removeAllSegments();
                removeAllUISegments();
              }}
            >
              {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.clearSegments)}
            </Button>
          )}
          <CopyPermissionsButton
            variant={readOnly ? 'emphasized' : 'default'}
            color={color}
          />
        </Flex>
      </MessageContainer.Actions>
    </MessageContainer>
  );
};
